function calculate(inputs) {
    const initialInvestment = inputs.initialInvestment;
    const annualEnergyProduction = inputs.annualEnergyProduction;
    const currentEnergyPrice = inputs.currentEnergyPrice;
    const annualOandM = inputs.annualOandM;
    const energyPriceInflationRate = inputs.energyPriceInflationRate / 100;
    const systemDegradationRate = inputs.systemDegradationRate / 100;
    const annualOandMInflationRate = inputs.annualOandMInflationRate / 100;
    const governmentIncentive = inputs.governmentIncentive;
    const projectLifespan = inputs.projectLifespan;

    let netInvestmentAfterIncentives = initialInvestment - governmentIncentive;

    // Handle case where incentives cover or exceed initial investment
    if (netInvestmentAfterIncentives <= 0) {
        let cumulativePositiveCashFlow = -netInvestmentAfterIncentives; // This is the immediate surplus
        let currentAnnualProductionForLifespan = annualEnergyProduction;
        let currentEnergyPriceForLifespan = currentEnergyPrice;
        let currentAnnualOandMForLifespan = annualOandM;

        for (let year = 1; year <= projectLifespan; year++) {
            if (year > 1) {
                currentAnnualProductionForLifespan *= (1 - systemDegradationRate);
                currentEnergyPriceForLifespan *= (1 + energyPriceInflationRate);
                currentAnnualOandMForLifespan *= (1 + annualOandMInflationRate);
            }
            const annualEnergySavings = currentAnnualProductionForLifespan * currentEnergyPriceForLifespan;
            const annualNetCashFlow = annualEnergySavings - currentAnnualOandMForLifespan;
            cumulativePositiveCashFlow += annualNetCashFlow;
        }

        return {
            paybackPeriod: 0,
            totalSavingsAtPayback: parseFloat((-netInvestmentAfterIncentives).toFixed(2)), // The immediate surplus
            cumulativeSavingsAfterLifespan: parseFloat(cumulativePositiveCashFlow.toFixed(2))
        };
    }

    let cumulativeCashFlowTracker = -netInvestmentAfterIncentives; // Starts negative (the remaining investment)
    let paybackPeriod = null;
    let totalSavingsAtPayback = 0;
    let cumulativeSavingsAfterLifespan = -netInvestmentAfterIncentives; // Initialize with the initial outlay

    let currentAnnualProduction = annualEnergyProduction;
    let currentEnergyPricePerKwh = currentEnergyPrice;
    let currentAnnualOandM = annualOandM;

    for (let year = 1; year <= projectLifespan; year++) {
        // Adjust for degradation (starts after year 1, as year 1 has full stated production)
        if (year > 1) {
            currentAnnualProduction *= (1 - systemDegradationRate);
        }

        // Adjust for energy price inflation (starts after year 1)
        if (year > 1) {
             currentEnergyPricePerKwh *= (1 + energyPriceInflationRate);
        }

        // Adjust for O&M inflation (starts after year 1)
        if (year > 1) {
            currentAnnualOandM *= (1 + annualOandMInflationRate);
        }

        const annualEnergySavings = currentAnnualProduction * currentEnergyPricePerKwh;
        const annualNetCashFlow = annualEnergySavings - currentAnnualOandM;

        cumulativeCashFlowTracker += annualNetCashFlow;
        cumulativeSavingsAfterLifespan += annualNetCashFlow;

        if (paybackPeriod === null && cumulativeCashFlowTracker >= 0) {
            // Payback occurs in this year. Calculate fractional year.
            const previousCumulativeCashFlow = cumulativeCashFlowTracker - annualNetCashFlow; // Value before this year's cash flow
            paybackPeriod = year - 1 + (-previousCumulativeCashFlow / annualNetCashFlow);
            totalSavingsAtPayback = parseFloat(cumulativeCashFlowTracker.toFixed(2)); // The net cash flow value when payback is achieved
        }
    }

    if (paybackPeriod === null) {
        paybackPeriod = "No Payback within Project Lifespan";
        totalSavingsAtPayback = 0; // No payback means no savings *at* payback point.
    }

    return {
        paybackPeriod: typeof paybackPeriod === 'number' ? parseFloat(paybackPeriod.toFixed(2)) : paybackPeriod,
        totalSavingsAtPayback: parseFloat(totalSavingsAtPayback.toFixed(2)),
        cumulativeSavingsAfterLifespan: parseFloat(cumulativeSavingsAfterLifespan.toFixed(2))
    };
}
